import socket
import threading
import json
import time
import math

class Player:
    def __init__(self, player_id, position):
        self.id = player_id
        self.position = position

class GameServer:
    def __init__(self, host='0.0.0.0', port=5000):
        self.players = {}
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((host, port))
        self.lock = threading.Lock()
        self.running = True

    def start(self):
        threading.Thread(target=self.receive_data).start()
        while self.running:
            self.broadcast_game_state()
            time.sleep(0.1)

    def receive_data(self):
        while self.running:
            data, addr = self.server_socket.recvfrom(1024)
            self.handle_client_data(data, addr)

    def handle_client_data(self, data, addr):
        try:
            player_data = json.loads(data.decode())
            player_id = player_data['id']
            position = player_data['position']
            with self.lock:
                self.players[player_id] = Player(player_id, position)
        except (json.JSONDecodeError, KeyError):
            pass

    def broadcast_game_state(self):
        with self.lock:
            game_state = {player_id: player.position for player_id, player in self.players.items()}
        for player in self.players.values():
            self.server_socket.sendto(json.dumps(game_state).encode(), (player.id, 5000))

    def stop(self):
        self.running = False
        self.server_socket.close()

if __name__ == "__main__":
    game_server = GameServer()
    try:
        game_server.start()
    except KeyboardInterrupt:
        game_server.stop()